-- อัพเดทชื่ออำเภอจากชื่อสถานพยาบาล
UPDATE hospitals SET district = 
    CASE 
        WHEN name LIKE '%ควนกาหลง%' THEN 'ควนกาหลง'
        WHEN name LIKE '%ควนโดน%' THEN 'ควนโดน'
        WHEN name LIKE '%ท่าแพ%' THEN 'ท่าแพ'
        WHEN name LIKE '%ทุ่งหว้า%' THEN 'ทุ่งหว้า'
        WHEN name LIKE '%มะนัง%' THEN 'มะนัง'
        WHEN name LIKE '%ละงู%' THEN 'ละงู'
        WHEN name LIKE '%สตูล%' OR name LIKE '%เมือง%' THEN 'เมืองสตูล'
        ELSE 'เมืองสตูล'
    END;
